            // ["uniqueOperands"] = n2,
            // ["totalOperators"] = N1,
            // ["totalOperands"] = N2,
            ["vocabulary"] = Vocabulary,
            ["length"] = Length,
            ["volume"] = Fix(Volume),
            ["difficulty"] = Fix(Difficulty),
            ["effort"] = Fix(Effort),
